1	//! Coroutine library — port of `lcorolib.c`.
2	//!
3	//! Provides the `coroutine.*` standard-library table: `create`, `resume`,
4	//! `running`, `status`, `wrap`, `yield`, `isyieldable`, and `close`.
5	//!
6	//! # Phase A–D stub notice
7	//!
8	//! Every function that requires actual coroutine execution (`resume`, `yield`,
9	//! cross-thread `xmove`, `new_thread`, `close_thread`) is **unimplemented** and
10	//! will panic at runtime.  The argument-checking and result-packaging logic is
11	//! translated faithfully so that Phase E can drop in the real implementations
12	//! without restructuring.  Phase E wires real stackful coroutines via
13	//! `corosensei`.  See PORTING.md §2 #6.
14	//!
15	//! Translated from: `reference/lua-5.4.7/src/lcorolib.c` (210 lines, 12 functions)
16	//! Target crate: `lua-stdlib`
17	
18	// TODO(port): LuaState, GcRef<LuaState>, LuaStatus, and related types live in
19	// lua-vm / lua-types; all unresolved imports will be fixed in Phase B.
20	use lua_types::{
21	    error::LuaError,
22	    value::LuaValue,
23	    LuaType,
24	    LuaStatus,
25	    gc::GcRef,
26	};
27	use crate::state_stub::{LuaState, LuaStateStubExt as _, lua_CFunction, upvalue_index, CompareOp, LuaDebug};
28	
29	// ── Coroutine status codes ────────────────────────────────────────────────────
30	
31	// C: #define COS_RUN   0
32	// C: #define COS_DEAD  1
33	// C: #define COS_YIELD 2
34	// C: #define COS_NORM  3
35	
36	/// Coroutine is the currently running thread.
37	const COS_RUN: i32 = 0;
38	
39	/// Coroutine has finished execution or encountered an error.
40	const COS_DEAD: i32 = 1;
41	
42	/// Coroutine is suspended — either yielded or not yet started.
43	const COS_YIELD: i32 = 2;
44	
45	/// Coroutine is normal — it resumed another coroutine and is waiting.
46	const COS_NORM: i32 = 3;
47	
48	/// Human-readable status strings indexed by the `COS_*` constants above.
49	/// Pushed onto the Lua stack as byte strings.
50	///
51	/// C: `static const char *const statname[] = {"running","dead","suspended","normal"};`
52	const STAT_NAMES: [&[u8]; 4] = [b"running", b"dead", b"suspended", b"normal"];
53	
54	// ── Registration table ────────────────────────────────────────────────────────
55	
56	/// Registration table for the `coroutine` standard library.
57	///
58	/// C: `static const luaL_Reg co_funcs[]`
59	///
60	/// Each entry is `(name_bytes, function_pointer)`. Phase B resolves
61	/// `lua_CFunction` to the canonical type alias from `lua-types`.
62	pub const CO_FUNCS: &[(&[u8], lua_CFunction)] = &[
63	    (b"create",      co_create),
64	    (b"resume",      co_resume),
65	    (b"running",     co_running),
66	    (b"status",      co_status),
67	    (b"wrap",        co_wrap),
68	    (b"yield",       co_yield),
69	    (b"isyieldable", co_isyieldable),
70	    (b"close",       co_close),
71	];
72	
73	// ── Internal helpers ──────────────────────────────────────────────────────────
74	
75	/// Retrieves the coroutine thread at stack index 1, raising a type error if
76	/// the argument is absent or not a thread.
77	///
78	/// C: `static lua_State *getco(lua_State *L)`
79	fn get_co(state: &mut LuaState) -> Result<GcRef<lua_types::value::LuaThread>, LuaError> {
80	    let co = state.to_thread(1);
81	    if co.is_none() {
82	        let got = state.arg(1);
83	        return Err(LuaError::type_arg_error(1, "thread", &got));
84	    }
85	    Ok(co.expect("checked above"))
86	}
87	
88	/// Returns one of the `COS_*` status codes describing `co` relative to the
89	/// calling thread `state`.
90	///
91	/// C: `static int auxstatus(lua_State *L, lua_State *co)`
92	fn aux_status(_state: &mut LuaState, _co: &GcRef<lua_types::value::LuaThread>) -> i32 {
93	    // TODO(phase-b): needs lua_vm cross-thread access to status, has_frames,
94	    // get_top, is_same_thread. Phase E wires real coroutines.
95	    todo!("phase-b: coroutine aux_status")
96	}
97	
98	/// Transfers `narg` arguments from `state` to `co`, resumes the coroutine,
99	/// then transfers results (or error message) back to `state`.
100	///
101	/// Returns the number of result values (≥ 0) on success, or `-1` on error
102	/// with the error object left on top of `state`'s stack.
103	///
104	/// C: `static int auxresume(lua_State *L, lua_State *co, int narg)`
105	fn aux_resume(state: &mut LuaState, _co: GcRef<lua_types::value::LuaThread>, _narg: i32) -> i32 {
106	    // Phase A–D stub: real cross-thread resume needs corosensei runtime
107	    // support (PORTING.md §2 #6 — Phase E).  Emulate C's `auxresume` error
108	    // path: push a string error object onto the caller's stack and return
109	    // -1.  `co_resume` packages this as `(false, msg)` and `aux_wrap`
110	    // re-raises it as a Lua error, matching C-Lua semantics on a coroutine
111	    // that cannot run.  Phase E will replace this body with the full
112	    // checkstack / xmove / lua_resume / xmove sequence.
113	    let msg_bytes: &[u8] = b"coroutines not yet implemented (Phase E)";
114	    match state.intern_str(msg_bytes) {
115	        Ok(s) => state.push(LuaValue::Str(s)),
116	        Err(_) => state.push(LuaValue::Nil),
117	    }
118	    -1
119	}
120	
121	// ── Public library functions ──────────────────────────────────────────────────
122	
123	/// `coroutine.resume(co [, val1, ...])` — attempt to resume coroutine `co`.
124	///
125	/// On success pushes `true` followed by all values yielded or returned by `co`.
126	/// On failure pushes `false` followed by the error object.
127	///
128	/// C: `static int luaB_coresume(lua_State *L)`
129	pub fn co_resume(state: &mut LuaState) -> Result<usize, LuaError> {
130	    // C: lua_State *co = getco(L);
131	    let co = get_co(state)?;
132	    // C: r = auxresume(L, co, lua_gettop(L) - 1);
133	    // PORT NOTE: lua_gettop returns the argument count; -1 excludes the coroutine
134	    // itself which sits at index 1.
135	    let narg = state.get_top() - 1;
136	    let r = aux_resume(state, co, narg);
137	    if r < 0 {
138	        // C: lua_pushboolean(L, 0); lua_insert(L, -2); return 2;
139	        state.push(LuaValue::Bool(false));
140	        state.insert(-2);
141	        Ok(2)
142	    } else {
143	        // C: lua_pushboolean(L, 1); lua_insert(L, -(r + 1)); return r + 1;
144	        state.push(LuaValue::Bool(true));
145	        state.insert(-(r + 1));
146	        Ok((r + 1) as usize)
147	    }
148	}
149	
150	/// Closure body installed by `coroutine.wrap`.  The wrapped coroutine is
151	/// stored in upvalue slot 1.
152	///
153	/// On error the message is augmented with location info (if a string), then
154	/// re-raised.  If the coroutine is in an error state (not simply suspended),
155	/// its to-be-closed variables are cleaned up before propagation.
156	///
157	/// C: `static int luaB_auxwrap(lua_State *L)`
158	fn aux_wrap(state: &mut LuaState) -> Result<usize, LuaError> {
159	    // C: lua_State *co = lua_tothread(L, lua_upvalueindex(1));
160	    // TODO(port): coroutine stub — upvalue_index(1) gives the first C-closure
161	    // upvalue pseudo-index; to_thread reads GcRef<LuaState> from that slot.
162	    let co = match state.to_thread(upvalue_index(1)) {
163	        Some(c) => c,
164	        None => panic!("coroutine.wrap: upvalue 1 is not a thread (Phase A–D stub)"),
165	    };
166	    // C: int r = auxresume(L, co, lua_gettop(L));
167	    let narg = state.get_top();
168	    let r = aux_resume(state, co.clone(), narg);
169	    let _ = co;
170	    if r < 0 {
171	        // Phase A–D stub: aux_resume placed an error object on top of the
172	        // caller's stack and returned -1.  C's `luaB_auxwrap` would consult
173	        // cross-thread status, close to-be-closed vars, and luaL_where-prefix
174	        // the message before propagating; until Phase E wires those, raise
175	        // the error value directly via `lua_error` semantics.
176	        let err_val = state.pop();
177	        Err(LuaError::from_value(err_val))
178	    } else {
179	        Ok(r as usize)
180	    }
181	}
182	
183	/// `coroutine.create(f)` — create a new coroutine that will run function `f`.
184	///
185	/// Pushes the new thread value and returns 1.
186	///
187	/// C: `static int luaB_cocreate(lua_State *L)`
188	pub fn co_create(state: &mut LuaState) -> Result<usize, LuaError> {
189	    // C: luaL_checktype(L, 1, LUA_TFUNCTION);
190	    state.check_arg_type(1, LuaType::Function)?;
191	    // C: NL = lua_newthread(L);
192	    // TODO(port): coroutine stub — new_thread allocates a fresh LuaState coroutine
193	    // and pushes a Thread value for it; Phase E needed.
194	    let _nl = state.new_thread()?;
195	    // C: lua_pushvalue(L, 1);          /* move function to top */
196	    // C: lua_xmove(L, NL, 1);          /* move function from L to NL */
197	    // PORT NOTE: in C the function copy is pushed and then xmove pops it
198	    // off L's stack into NL's. The Phase E xmove is not yet wired, but the
199	    // net stack effect on L is "thread on top". Skip the push entirely so
200	    // co_wrap's push_cclosure captures the thread (not the function) as
201	    // upvalue 1. Phase E will restore the push + xmove pair.
202	    // TODO(port): coroutine stub — xmove transfers the function from L's stack to
203	    // NL's stack so it becomes the coroutine body; Phase E needed.
204	    Ok(1)
205	}
206	
207	/// `coroutine.wrap(f)` — create a coroutine and return a resuming function.
208	///
209	/// The returned function, when called, resumes the coroutine as if by
210	/// `coroutine.resume`, but raises an error rather than returning `false`.
211	///
212	/// C: `static int luaB_cowrap(lua_State *L)`
213	pub fn co_wrap(state: &mut LuaState) -> Result<usize, LuaError> {
214	    // C: luaB_cocreate(L);
215	    co_create(state)?;
216	    // C: lua_pushcclosure(L, luaB_auxwrap, 1);
217	    // TODO(port): push_cclosure(aux_wrap, 1) creates a C closure with the thread
218	    // (currently on top of the stack) as upvalue 1; Phase B wire-up needed.
219	    state.push_cclosure(aux_wrap, 1)?;
220	    Ok(1)
221	}
222	
223	/// `coroutine.yield([...])` — suspend the running coroutine.
224	///
225	/// All arguments are passed back as results of the corresponding `resume`.
226	///
227	/// C: `static int luaB_yield(lua_State *L)`
228	pub fn co_yield(state: &mut LuaState) -> Result<usize, LuaError> {
229	    // Phase A–D stub: real `lua_yield` needs corosensei stackful coroutines
230	    // (PORTING.md §2 #6 — Phase E).  Raise a Lua error so callers can pcall
231	    // gracefully rather than crashing the host with a Rust panic.
232	    let _nargs = state.get_top();
233	    Err(LuaError::runtime(format_args!(
234	        "coroutine.yield: coroutines not yet implemented (Phase E)"
235	    )))
236	}
237	
238	/// `coroutine.status(co)` — return a string describing `co`'s current status.
239	///
240	/// Returns one of `"running"`, `"dead"`, `"suspended"`, or `"normal"`.
241	///
242	/// C: `static int luaB_costatus(lua_State *L)`
243	pub fn co_status(state: &mut LuaState) -> Result<usize, LuaError> {
244	    // C: lua_State *co = getco(L);
245	    let co = get_co(state)?;
246	    // C: lua_pushstring(L, statname[auxstatus(L, co)]);
247	    let idx = aux_status(state, &co) as usize;
248	    let name: &[u8] = STAT_NAMES[idx];
249	    let interned = state.intern_str(name)?;
250	    state.push(LuaValue::Str(interned));
251	    Ok(1)
252	}
253	
254	/// `coroutine.isyieldable([co])` — test whether a coroutine (default: current)
255	/// is in a yieldable state.
256	///
257	/// C: `static int luaB_yieldable(lua_State *L)`
258	pub fn co_isyieldable(state: &mut LuaState) -> Result<usize, LuaError> {
259	    let is_yieldable = if matches!(state.type_at(1), LuaType::None) {
260	        state.is_yieldable()
261	    } else {
262	        let _co = get_co(state)?;
263	        // TODO(phase-b): needs cross-thread is_yieldable; Phase E.
264	        todo!("phase-b: cross-thread is_yieldable")
265	    };
266	    state.push(LuaValue::Bool(is_yieldable));
267	    Ok(1)
268	}
269	
270	/// `coroutine.running()` — return the current coroutine plus a boolean.
271	///
272	/// The boolean is `true` when the current coroutine is the main thread.
273	///
274	/// C: `static int luaB_corunning(lua_State *L)`
275	pub fn co_running(state: &mut LuaState) -> Result<usize, LuaError> {
276	    // C: int ismain = lua_pushthread(L);
277	    // TODO(port): push_thread pushes a Thread value for the current LuaState and
278	    // returns true iff it is the main thread; Phase B wire-up needed.
279	    let is_main = state.push_thread()?;
280	    // C: lua_pushboolean(L, ismain);
281	    state.push(LuaValue::Bool(is_main));
282	    Ok(2)
283	}
284	
285	/// `coroutine.close(co)` — close a dead or suspended coroutine.
286	///
287	/// Runs the to-be-closed variable finalizers.  Returns `true` on success, or
288	/// `false` plus an error object on failure.  Raises an error if `co` is
289	/// running or normal.
290	///
291	/// C: `static int luaB_close(lua_State *L)`
292	pub fn co_close(state: &mut LuaState) -> Result<usize, LuaError> {
293	    let co = get_co(state)?;
294	    let status = aux_status(state, &co);
295	    match status {
296	        s if s == COS_DEAD || s == COS_YIELD => {
297	            // TODO(phase-b): needs cross-thread close_thread + xmove.
298	            todo!("phase-b: coroutine close")
299	        }
300	        _ => {
301	            let name = match status {
302	                COS_RUN => "running",
303	                COS_NORM => "normal",
304	                _ => "unknown",
305	            };
306	            Err(LuaError::runtime(format_args!(
307	                "cannot close a {} coroutine",
308	                name
309	            )))
310	        }
311	    }
312	}
313	
314	// ── Module entry point ────────────────────────────────────────────────────────
315	
316	/// Opens the `coroutine` standard library by pushing a new table containing
317	/// all `coroutine.*` functions.
318	///
319	/// C: `LUAMOD_API int luaopen_coroutine(lua_State *L)` — `LUAMOD_API` → `pub`.
320	pub fn open_coroutine(state: &mut LuaState) -> Result<usize, LuaError> {
321	    // C: luaL_newlib(L, co_funcs);
322	    // TODO(port): state.new_lib(CO_FUNCS) creates a table from the registration
323	    // slice and leaves it on the stack; Phase B wire-up needed.
324	    state.new_lib(CO_FUNCS)?;
325	    Ok(1)
326	}
327	
328	// ──────────────────────────────────────────────────────────────────────────────
329	// PORT STATUS
330	//   source:        src/lcorolib.c  (210 lines, 12 functions)
331	//   target_crate:  lua-stdlib
332	//   confidence:    medium
333	//   todos:         21
334	//   port_notes:    2
335	//   unsafe_blocks: 0
336	//   notes:         All coroutine execution primitives (resume, yield, xmove,
337	//                  new_thread, close_thread) are Phase E stubs that panic.
338	//                  Argument-checking / result-packaging logic is faithfully
339	//                  translated so Phase E can drop in real implementations.
340	//                  The CO_FUNCS table type references lua_CFunction which is
341	//                  resolved in Phase B.  LuaState / GcRef<LuaState> / LuaStatus
342	//                  imports are all deferred to Phase B.
343	// ──────────────────────────────────────────────────────────────────────────────
